const chatId = $('When Executed by Another Workflow').first().json.chat_id;
const items = $input.all().map(item => item.json);
if (!items || items.length === 0 || Object.keys(items[0]).length === 0) {
  return [{ json: { message: '📭 No schedule data available.', chat_id: chatId } }];
}

// Extract unique time slots and courts
const timeslots = [...new Set(items.map(x => x.time_slot))].sort();
const courts = [...new Set(items.map(x => x.court_number))].sort();

// Get the date from first item - fix UTC timezone shift
let scheduleDate = 'Unknown date';
if (items[0]?.date) {
  const d = new Date(items[0].date);
  scheduleDate = d.toLocaleDateString('sv-SE', { timeZone: 'Europe/Warsaw' });
}

// Build header
let message = `<b>🏸 Court Schedule</b>\n`;
message += `<b>📅 ${scheduleDate}</b>\n\n`;

// Build monospace table header
message += '<pre>';
message += '🕓     ';
courts.forEach(court => {
  const courtNum = court.replace('Badminton ', '#');
  message += `${courtNum} `;
});
message += '\n';
message += '───────' + '────'.repeat(courts.length) + '\n';

const available_times = Object.entries(
  $input.all().map(i => i.json)
    .filter(slot => slot.is_available)
    .reduce((acc, slot) => {
      const time = slot.time_slot.slice(0, 5);
      const court = slot.court_number.replace('Badminton ', '');
      acc[time] = acc[time] || [];
      acc[time].push(court);
      return acc;
    }, {})
).map(([time_slot, courts]) => ({ time_slot, courts }));

// Build table rows
timeslots.forEach(ts => {
  let timeDisplay = ts;
  if (ts.includes('T')) {
    timeDisplay = ts.substring(11, 16);
  } else if (ts.length > 5) {
    timeDisplay = ts.substring(0, 5);
  }
  message += timeDisplay + '  ';

  courts.forEach(court => {
    const slot = items.find(item => 
      item.time_slot === ts && item.court_number === court
    );

    if (!slot) {
      message += '⬜ ';
    } else if (slot.bot_user_id) {
      message += '🏸 ';  // booked by a bot user (takes priority — handles pre-sync window)
    } else if (slot.is_available) {
      message += '✅ ';
    } else {
      message += '❌ ';  // booked externally
    }
  });
  message += '\n';
});

message += '</pre>';
message += '\n✅ Available  🏸 Bot booking  ❌ External';

const botSlots = items.filter(item => item.bot_user_id);
if (botSlots.length > 0) {
  message += '\n\n<b>📋 Bot Reservations:</b>';
  const byUser = {};
  botSlots.forEach(slot => {
    const key = slot.bot_user_id;
    if (!byUser[key]) {
      byUser[key] = {
        name: slot.bot_user_name || slot.bot_username || `user ${slot.bot_user_id}`,
        username: slot.bot_username ? `@${slot.bot_username}` : '',
        slots: []
      };
    }
    const timeDisplay = (slot.time_slot || '').substring(0, 5);
    const courtNum = slot.court_number.replace('Badminton ', '#');
    byUser[key].slots.push(`${courtNum} ${timeDisplay}`);
  });
  Object.values(byUser).forEach(u => {
    const displayName = u.username ? `${u.name} (${u.username})` : u.name;
    message += `\n• <b>${displayName}</b>: ${u.slots.join(', ')}`;
  });
}

return [{ json: { message: message, chat_id: chatId, available_times: available_times } }];

const arg1 = $input.first().json.arg1;
const ctx = $input.first().json;

// No date provided → pass through
if (!arg1) {
  return [{ json: { ...ctx, resolved_date: null, ambiguous: false, interpretations: [] } }];
}

// Already ISO (YYYY-MM-DD) → unambiguous
if (/^\d{4}-\d{2}-\d{2}$/.test(String(arg1).trim())) {
  return [{ json: { ...ctx, resolved_date: arg1, ambiguous: false, interpretations: [] } }];
}

// Match flexible format: A.B.C, A/B/C, A-B-C
const m = String(arg1).trim().match(/^(\d{1,4})[\.\/-](\d{1,2})(?:[\.\/-](\d{2,4}))?$/);
if (!m) {
  return [{ json: { ...ctx, resolved_date: arg1, ambiguous: false, interpretations: [] } }];
}

const [_, a, b, c] = m;
const aNum = parseInt(a), bNum = parseInt(b);

let year;
if (c) {
  const cNum = parseInt(c);
  year = c.length === 4 ? cNum : 2000 + cNum;
} else {
  year = new Date().getFullYear();
}

function isValidDate(y, mo, d) {
  if (mo < 1 || mo > 12 || d < 1) return false;
  return d <= new Date(y, mo, 0).getDate();
}

function toISO(y, mo, d) {
  return `${y}-${String(mo).padStart(2,'0')}-${String(d).padStart(2,'0')}`;
}

if (aNum > 12) {
  const iso = isValidDate(year, bNum, aNum) ? toISO(year, bNum, aNum) : arg1;
  return [{ json: { ...ctx, resolved_date: iso, ambiguous: false, interpretations: [] } }];
}

if (bNum > 12) {
  const iso = isValidDate(year, aNum, bNum) ? toISO(year, aNum, bNum) : arg1;
  return [{ json: { ...ctx, resolved_date: iso, ambiguous: false, interpretations: [] } }];
}

const ddMM = isValidDate(year, bNum, aNum) ? toISO(year, bNum, aNum) : null;
const MMdd = isValidDate(year, aNum, bNum) ? toISO(year, aNum, bNum) : null;

if (ddMM && MMdd && ddMM !== MMdd) {
  return [{ json: { ...ctx, resolved_date: null, ambiguous: true, interpretations: [ddMM, MMdd] } }];
}

const resolved = ddMM || MMdd || arg1;
return [{ json: { ...ctx, resolved_date: resolved, ambiguous: false, interpretations: [] } }];

const crypto = require('crypto');
const ctx = $input.first().json;

const confirmation_id = crypto.randomBytes(8).toString('hex');

function formatDate(iso, lang) {
  const locales = { pl: 'pl-PL', ru: 'ru-RU', en: 'en-GB' };
  const locale = locales[lang] || 'en-GB';
  return new Date(iso).toLocaleDateString(locale, { day: 'numeric', month: 'long', year: 'numeric' });
}

const lang = ctx.lang || 'en';
const [date1, date2] = ctx.interpretations;

return [{
  json: {
    ...ctx,
    confirmation_id,
    button_text_1: formatDate(date1, lang),
    button_text_2: formatDate(date2, lang),
    callback_date_1: date1,
    callback_date_2: date2,
  }
}];

